eState({}); // TODO: demonstrate one is selected\n\n    // TODO(docs): Why must `any` be passed as second type param to avoid `unknown`?\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const selectableColumns = React.useMemo<DataTableUtils.ColumnDef<Person, any>[]>(() => [{\n      id: 'select',\n      header: ({\n        table\n      }) => <DataTable.HeaderCell>\n              <Checkbox {...{\n          checked: table.getIsAllRowsSelected(),\n          indeterminate: table.getIsSomeRowsSelected(),\n          onChange: table.getToggleAllRowsSelectedHandler(),\n          'aria-label': 'check'\n        }} />\n            </DataTable.HeaderCell>,\n      cell: ({\n        row\n      }) => <DataTable.DataCell>\n              <Checkbox {...{\n          checked: row.getIsSelected(),\n          disabled: !row.getCanSelect(),\n          indeterminate: row.getIsSomeSelected(),\n          onChange: row.getToggleSelectedHandler(),\n          'aria-label': 'check'\n        }} />\n            </DataTable.DataCell>,\n      // Widths can be set on header cells (using pixels)\n      // More information: https://tanstack.com/table/latest/docs/guide/column-sizing#column-widths\n      // TODO(design): what is the column size for the selectable column\n      size: 32\n    }, columnHelper.accessor('firstName', {\n      header: () => <DataTable.HeaderCell leadingIcon=\"person-add\" sortDirection=\"ascending\" subLabel=\"Given Name\">\n              First Name\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell leadingIcon=\"person-add\">\n              {info.getValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor(row => row.lastName, {\n      id: 'lastName',\n      header: () => <DataTable.HeaderCell subLabel=\"Surname\">\n              Last Name\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell>{info.getValue()}</DataTable.DataCell>\n    }), columnHelper.accessor('age', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\">\n              Age\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\">\n              {info.renderValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor('visits', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\">\n              Visits\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\">\n              {info.renderValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor('progress', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\" subLabel='\"Complete\" is > 80%'>\n              Profile Progress\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\" subLabel={Number(info.renderValue()) >= 80 ? 'Complete' : 'Incomplete'}>\n              {info.renderValue()}\n            </DataTable.DataCell>\n    })], []);\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const table = DataTableUtils.useReactTable({\n      data: defaultData,\n      columns: selectableColumns,\n      state: {\n        rowSelection\n      },\n      enableRowSelection: true,\n      onRowSelectionChange: setRowSelection,\n      getCoreRowModel: DataTableUtils.getCoreRowModel()\n    });\n    return <DataTable {...args} table={table} />;\n  }\n}",...Selectable.parameters?.docs?.source},description:{story:"Implementation example of how to build selectable rows.\n\nFor more information: https://tanstack.com/table/latest/docs/framework/react/examples/row-selection",...Selectable.parameters?.docs?.description}}},VerticalDivider.parameters={...VerticalDivider.parameters,docs:{...VerticalDivider.parameters?.docs,source:{originalSource:"{\n  args: {\n    caption: 'Test table',\n    subCaption: 'Additional Subcaption',\n    isInteractive: true\n  },\n  parameters: {\n    chromatic: {\n      diffThreshold: 0.75\n    }\n  },\n  render: args => {\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const [rowSelection, setRowSelection] = React.useState({});\n\n    // TODO(docs): Why must `any` be passed as second type param to avoid `unknown`?\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const selectableColumns = React.useMemo<DataTableUtils.ColumnDef<Person, any>[]>(() => [{\n      id: 'select',\n      header: ({\n        table\n      }) => <DataTable.HeaderCell>\n              <Checkbox {...{\n          checked: table.getIsAllRowsSelected(),\n          indeterminate: table.getIsSomeRowsSelected(),\n          onChange: table.getToggleAllRowsSelectedHandler(),\n          'aria-label': 'check'\n        }} />\n            </DataTable.HeaderCell>,\n      cell: ({\n        row\n      }) => <DataTable.DataCell>\n              <Checkbox {...{\n          checked: row.getIsSelected(),\n          disabled: !row.getCanSelect(),\n          indeterminate: row.getIsSomeSelected(),\n          onChange: row.getToggleSelectedHandler(),\n          'aria-label': 'check'\n        }} />\n            </DataTable.DataCell>,\n      // Widths can be set on header cells (using pixels)\n      // More information: https://tanstack.com/table/latest/docs/guide/column-sizing#column-widths\n      // TODO(design): what is the column size for the selectable column\n      size: 32\n    }, columnHelper.accessor('firstName', {\n      header: () => <DataTable.HeaderCell hasHorizontalDivider leadingIcon=\"person-add\" sortDirection=\"ascending\" subLabel=\"Given Name\">\n              First Name\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell hasHorizontalDivider leadingIcon=\"person-add\">\n              {info.getValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor(row => row.lastName, {\n      id: 'lastName',\n      header: () => <DataTable.HeaderCell hasHorizontalDivider subLabel=\"Surname\">\n              Last Name\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell hasHorizontalDivider>\n              {info.getValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor('age', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\" hasHorizontalDivider>\n              Age\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\" hasHorizontalDivider>\n              {info.renderValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor('visits', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\" hasHorizontalDivider>\n              Visits\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\" hasHorizontalDivider>\n              {info.renderValue()}\n            </DataTable.DataCell>\n    }), columnHelper.accessor('progress', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\" hasHorizontalDivider subLabel='\"Complete\" is > 80%'>\n              Profile Progress\n            </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\" hasHorizontalDivider subLabel={Number(info.renderValue()) >= 80 ? 'Complete' : 'Incomplete'}>\n              {info.renderValue()}\n            </DataTable.DataCell>\n    })], []);\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const table = DataTableUtils.useReactTable({\n      data: defaultData,\n      columns: selectableColumns,\n      state: {\n        rowSelection\n      },\n      enableRowSelection: true,\n      onRowSelectionChange: setRowSelection,\n      getCoreRowModel: DataTableUtils.getCoreRowModel()\n    });\n    return <DataTable {...args} table={table} />;\n  }\n}",...VerticalDivider.parameters?.docs?.source},description:{story:"Implementation example of how to build selectable rows.\n\nTODO: verify if selection will interfere with row groupings\n\nFor more information: https://tanstack.com/table/latest/docs/framework/react/examples/row-selection",...VerticalDivider.parameters?.docs?.description}}},Grouping.parameters={...Grouping.parameters,docs:{...Grouping.parameters?.docs,source:{originalSource:"{\n  args: {\n    caption: 'Types of Wine',\n    tableStyle: 'border',\n    rowStyle: 'lined'\n  },\n  render: args => {\n    type Wine = {\n      name: string;\n      country?: string;\n      year?: number;\n    };\n    type GroupedWine = Wine & {\n      wines?: Wine[];\n    };\n    const wineData: GroupedWine[] = [{\n      name: 'Reds',\n      wines: [{\n        name: 'Merlot',\n        country: 'France',\n        year: 2016\n      }, {\n        name: 'Pinot Noir',\n        country: 'France',\n        year: 2018\n      }, {\n        name: 'Chianti',\n        country: 'Italy',\n        year: 2018\n      }]\n    }, {\n      name: 'Whites',\n      wines: [{\n        name: 'Chardonnay',\n        country: 'France',\n        year: 2016\n      }, {\n        name: 'Riesling',\n        country: 'Germany',\n        year: 2018\n      }]\n    }, {\n      name: 'Rosés',\n      wines: [{\n        name: 'Rosado',\n        country: 'Spain',\n        year: 2021\n      }, {\n        name: 'Rosato',\n        country: 'Italy',\n        year: 2024\n      }]\n    }];\n    const columnHelper = DataTableUtils.createColumnHelper<GroupedWine>();\n    const wineColumns = [columnHelper.accessor('name', {\n      header: () => <DataTable.HeaderCell>Name</DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell>{info.getValue()}</DataTable.DataCell>\n    }), columnHelper.accessor('country', {\n      id: 'lastName',\n      header: () => <DataTable.HeaderCell>Country of Origin</DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell>{info.getValue()}</DataTable.DataCell>\n    }), columnHelper.accessor('year', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\">Year</DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\">\n            {info.renderValue()}\n          </DataTable.DataCell>\n    })];\n\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const table = DataTableUtils.useReactTable({\n      data: wineData,\n      columns: wineColumns,\n      getSubRows: row => row.wines,\n      getCoreRowModel: DataTableUtils.getCoreRowModel(),\n      getExpandedRowModel: DataTableUtils.getExpandedRowModel()\n    });\n    return <DataTable {...args} table={table} />;\n  }\n}",...Grouping.parameters?.docs?.source},description:{story:"Implementation example showing how you can achieve grouping by creating a nested data object,\nand specify that grouping should be enabled in the data models.\n\nSee:\n- https://tanstack.com/table/latest/docs/guide/expanding\n- https://tanstack.com/table/latest/docs/api/core/row#getleafrows",...Grouping.parameters?.docs?.description}}},StatusRows.parameters={...StatusRows.parameters,docs:{...StatusRows.parameters?.docs,source:{originalSource:"{\n  args: {\n    caption: 'Test table',\n    subCaption: 'Additional Subcaption',\n    isStatusEligible: true,\n    tableStyle: 'border',\n    rowStyle: 'lined',\n    size: 'sm'\n  },\n  render: args => {\n    const columns = [columnHelper.accessor(DataTable.__StatusColumnId__, {\n      header: () => <DataTable.StatusHeaderCell />,\n      cell: info => <DataTable.StatusCell status={info.getValue()} />,\n      size: 32\n    }), columnHelper.accessor('firstName', {\n      header: () => <DataTable.HeaderCell sortDirection=\"ascending\">\n            First Name\n          </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell>{info.getValue()}</DataTable.DataCell>\n    }), columnHelper.accessor(row => row.lastName, {\n      id: 'lastName',\n      header: () => <DataTable.HeaderCell>Last Name</DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell>{info.getValue()}</DataTable.DataCell>\n    }), columnHelper.accessor('age', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\">Age</DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\">\n            {info.renderValue()}\n          </DataTable.DataCell>\n    }), columnHelper.accessor('visits', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\">\n            Visits\n          </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\">\n            {info.renderValue()}\n          </DataTable.DataCell>\n    }), columnHelper.accessor('progress', {\n      header: () => <DataTable.HeaderCell alignment=\"trailing\">\n            Profile Progress\n          </DataTable.HeaderCell>,\n      cell: info => <DataTable.DataCell alignment=\"trailing\">\n            {info.renderValue()}\n          </DataTable.DataCell>\n    })];\n\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const table = DataTableUtils.useReactTable({\n      data: defaultData,\n      columns,\n      getCoreRowModel: DataTableUtils.getCoreRowModel()\n    });\n    return <DataTable {...args} table={table} />;\n  }\n}",...StatusRows.parameters?.docs?.source},description:{story:"You can specify detailed statuses for each row in a table, matching a few common options.\nExtend the data type to include `status` which maps to the internal type\n\nUse `DataTableWithStatus` on your data type model to add in the column handler. this\nwill add add a `status` item, to be used with a column with header name `DataTable.__StatusColumnId__`.",...StatusRows.parameters?.docs?.description}}},HorizontalScrolling.parameters={...HorizontalScrolling.parameters,docs:{...HorizontalScrolling.parameters?.docs,source:{originalSource:"{\n  args: {\n    tableStyle: 'border',\n    size: 'sm'\n  },\n  render: args => {\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const table = DataTableUtils.useReactTable({\n      data: [...defaultData, ...defaultData],\n      columns,\n      getCoreRowModel: DataTableUtils.getCoreRowModel(),\n      initialState: {\n        columnPinning: {\n          left: ['firstName']\n        }\n      }\n    });\n    return <DataTable {...args} className=\"w-[800px]\" table={table} />;\n  }\n}",...HorizontalScrolling.parameters?.docs?.source},description:{story:"Allow for fixing some columns to not scroll off the screen, like freezing a column\n\n* This first column is sticky by default\n* Subsequent rows can be made sticky as well\n\nSee: https://tanstack.com/table/latest/docs/framework/react/examples/column-pinning-sticky\nSee: https://tanstack.com/table/latest/docs/guide/column-pinning",...HorizontalScrolling.parameters?.docs?.description}}},DefaultWithCustomTable.parameters={...DefaultWithCustomTable.parameters,docs:{...DefaultWithCustomTable.parameters?.docs,source:{originalSource:'{\n  args: {\n    children: <table>\n        <tbody className="border-2 border-utility-default-lowEmphasis-hover">\n          <tr>\n            <td>Custom or standard table rows/cells here</td>\n          </tr>\n        </tbody>\n      </table>\n  }\n}',...DefaultWithCustomTable.parameters?.docs?.source}}},WithBasicCaption.parameters={...WithBasicCaption.parameters,docs:{...WithBasicCaption.parameters?.docs,source:{originalSource:"{\n  args: {\n    ...DefaultWithCustomTable.args,\n    caption: 'Fruits of the world'\n  }\n}",...WithBasicCaption.parameters?.docs?.source}}},WithFullCaption.parameters={...WithFullCaption.parameters,docs:{...WithFullCaption.parameters?.docs,source:{originalSource:"{\n  ...DefaultWithCustomTable,\n  args: {\n    ...DefaultWithCustomTable.args,\n    caption: 'Fruits of the world',\n    subCaption: \"Aren't they all so delicious?\"\n  }\n}",...WithFullCaption.parameters?.docs?.source}}},WithSearch.parameters={...WithSearch.parameters,docs:{...WithSearch.parameters?.docs,source:{originalSource:"{\n  args: {\n    ...DefaultWithCustomTable.args,\n    caption: 'Fruits of the world',\n    subCaption: \"Aren't they all so delicious?\",\n    onSearchChange: () => {}\n  }\n}",...WithSearch.parameters?.docs?.source}}},WithOnlyActions.parameters